```typescript
// src/dashboard/services/realtime.service.ts
export class RealtimeService {
  private subscriptions = new Map<WebSocket, Set<string>>();

  subscribe(socket: WebSocket, channel: string) {
    if (!this.subscriptions.has(socket)) {
      this.subscriptions.set(socket, new Set());
    }
    this.subscriptions.get(socket)!.add(channel);
  }

  unsubscribe(socket: WebSocket, channel: string) {
    this.subscriptions.get(socket)?.delete(channel);
  }

  broadcast(event: string, data: any, channel?: string) {
    const message = JSON.stringify({ event, data });

    this.subscriptions.forEach((channels, socket) => {
      if (!channel || channels.has(channel) || channels.has('all')) {
        socket.send(message);
      }
    });
  }
}
```

